import{_ as e,o as r,c as i,a4 as l}from"./chunks/framework.BhEBm8_q.js";const _=JSON.parse('{"title":"매직보관함","description":"","frontmatter":{},"headers":[],"relativePath":"09-magic-library.md","filePath":"09-magic-library.md"}'),t={name:"09-magic-library.md"};function o(n,a,c,d,p,h){return r(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="매직보관함" tabindex="-1">매직보관함 <a class="header-anchor" href="#매직보관함" aria-label="Permalink to “매직보관함”">​</a></h1><p><em>폴더 스캔과 색인 상태</em></p><p>매직보관함(매직 책장)은 사용자가 선택한 폴더를 스캔해 흩어진 문서를 자동으로 모아 주는 공간입니다. 파일을 하나씩 추가하지 않아도 됩니다.</p><h2 id="폴더-스캔" tabindex="-1">폴더 스캔 <a class="header-anchor" href="#폴더-스캔" aria-label="Permalink to “폴더 스캔”">​</a></h2><p>폴더를 선택하면 그 안의 지원 문서를 찾아 목록으로 만들고 본문을 색인합니다. 색인이 끝나면 그 문서들은 보관함 본문 검색의 대상이 됩니다. 여러 폴더를 추가해 관리할 수 있고, 폴더를 바꾸거나 제거할 수도 있습니다.</p><h2 id="증분-스캔" tabindex="-1">증분 스캔 <a class="header-anchor" href="#증분-스캔" aria-label="Permalink to “증분 스캔”">​</a></h2><p>다시 스캔할 때는 파일의 수정 시간, 크기, 해시를 비교해 바뀐 문서만 다시 처리합니다. 그래서 문서가 수백 개여도 두 번째 스캔부터는 빠릅니다. 새로 생긴 파일은 추가하고, 사라진 파일은 정리합니다.</p><h2 id="진행-상태-보기" tabindex="-1">진행 상태 보기 <a class="header-anchor" href="#진행-상태-보기" aria-label="Permalink to “진행 상태 보기”">​</a></h2><p>스캔과 색인은 백그라운드에서 진행되며, 진행률과 함께 취소할 수 있습니다. 화면이 멈추지 않으므로 색인 중에도 다른 문서를 읽을 수 있습니다.</p><h2 id="색인-상태와-실패-처리" tabindex="-1">색인 상태와 실패 처리 <a class="header-anchor" href="#색인-상태와-실패-처리" aria-label="Permalink to “색인 상태와 실패 처리”">​</a></h2><p>각 문서는 다음 상태로 관리됩니다.</p><ul><li>대기(pending) → 색인중 → 완료(done)</li><li>실패(failed)</li></ul><p>정책은 다음과 같습니다.</p><ul><li>한 문서의 색인이 실패해도 다른 문서 사용은 계속할 수 있습니다.</li><li>실패한 문서는 다시 시도할 수 있습니다.</li><li>CBZ/CB7처럼 텍스트가 없는 문서는 &quot;텍스트 없음&quot;으로 완료 처리됩니다.</li></ul><blockquote><p>매직보관함은 원본 폴더를 그대로 두고 목록·색인만 만듭니다. 원본 파일을 옮기거나 바꾸지 않습니다.</p></blockquote>',15)])])}const m=e(t,[["render",o]]);export{_ as __pageData,m as default};
